import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Milestone, MilestoneStatus } from '../../core/models';

/**
 * SiteView milestones — a vertical timeline with status badges
 * (pending / done / late). Planners get an "Add milestone" action; viewers
 * are read-only.
 *
 * DATA CONTRACT: `milestones` is a signal<Milestone[]> of mock data; the
 * service_agent stage clears it and wires ApiService.listMilestones() in ngOnInit.
 */
@Component({
  selector: 'app-milestones',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './milestones.component.html',
  styleUrl: './milestones.component.css',
})
export class MilestonesComponent implements OnInit {
  readonly projectId = signal<string>('');

  readonly milestones = signal<Milestone[]>([
    { id: 'm1', projectId: 'p1', name: 'Permits approved', dueOn: '2026-02-20', status: 'done' },
    { id: 'm2', projectId: 'p1', name: 'Foundation inspection passed', dueOn: '2026-04-18', status: 'done' },
    { id: 'm3', projectId: 'p1', name: 'Structural frame topped out', dueOn: '2026-05-15', status: 'late' },
    { id: 'm4', projectId: 'p1', name: 'Building dried-in (weather-tight)', dueOn: '2026-06-20', status: 'pending' },
    { id: 'm5', projectId: 'p1', name: 'Final occupancy inspection', dueOn: '2026-08-01', status: 'pending' },
  ]);

  readonly sorted = computed(() =>
    [...this.milestones()].sort((a, b) => Date.parse(a.dueOn) - Date.parse(b.dueOn)),
  );

  readonly counts = computed(() => {
    const c = { done: 0, pending: 0, late: 0 } as Record<MilestoneStatus, number>;
    for (const m of this.milestones()) c[m.status]++;
    return c;
  });

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.route.parent?.paramMap.subscribe((p) => this.projectId.set(p.get('id') ?? ''));
  }

  fmt(iso: string): string {
    return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  }
  statusLabel(s: MilestoneStatus): string {
    return { pending: 'Pending', done: 'Done', late: 'Late' }[s];
  }
  statusClass(s: MilestoneStatus): string {
    return { pending: 'badge-muted', done: 'badge-ok', late: 'badge-danger' }[s];
  }
  dotClass(s: MilestoneStatus): string {
    return { pending: 'pending', done: 'done', late: 'late' }[s];
  }
}
